import java.util.*;
import java.lang.*;
import java.io.*;
import java.util.Scanner;

class LinkedList {

    // Definition of Node structure
    static class Node {
        int data;
        Node next;

        Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    // Function to print the linked list
    public static void printList(Node head) {
        Node temp = head;
        while (temp != null) {
            if (temp.next != null) {
                System.out.print(temp.data + " -> ");
            } else {
                System.out.print(temp.data);
            }
            temp = temp.next;
        }
        System.out.println();
    }

    // Iterative function to reverse the linked list
    public static Node reverseIterative(Node head) {
        Node prev = null;
        Node current = head;
        Node next = null;

        while (current != null) {
            next = current.next;
            current.next = prev;
            prev = current;
            current = next;
        }
        return prev;  // New head of the reversed list
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        Node head = null;
        Node temp = null;

        // Creating the linked list
        for (int i = 0; i < n; i++) {
            int data = sc.nextInt();
            Node newNode = new Node(data);
            if (head == null) {
                head = newNode;
            } else {
                temp.next = newNode;
            }
            temp = newNode;
        }

        // Reversing the list iteratively
        head = reverseIterative(head);
        printList(head);

        sc.close();
    }
}
